//
// HELPERS
//
function go(id){document.querySelectorAll('.scr').forEach(s=>s.classList.remove('on'));document.getElementById('s-'+id).classList.add('on');window.scrollTo(0,0)}
function pick(a){return a[0|Math.random()*a.length]}
function shuffle(a){const r=[...a];for(let i=r.length-1;i>0;i--){const j=0|Math.random()*(i+1);[r[i],r[j]]=[r[j],r[i]]}return r}
function rnd(a,b){return Math.floor(Math.random()*(b-a+1))+a}

