function sanitizePool(list){
  return (list || []).filter(q => q && Number.isFinite(q.g) && typeof q.q === 'string' && Array.isArray(q.opts) && q.opts.length >= 2 && typeof q.a === 'string');
}

Object.keys(QBANK).forEach(key => {
  QBANK[key] = sanitizePool(QBANK[key]);
});

QBANK.mathall = sanitizePool([...(QBANK.math || []), ...(QBANK.algebra || []), ...(QBANK.geometry || [])]).filter(q => q.g >= 3);

