//
// STATE
//
let curSubject = null;
let questions = [];    // selected questions for this session
let qIndex = 0;
let curGrade = 5;      // adaptive current grade
let gradeStats = {};   // {grade: {ok:N, total:N, topics:[]}}
let answers = [];      // {q, grade, topic, correct}
let correctStreak = 0;
let wrongStreak = 0;
const MAX_Q = 20;
const DIAG_ACTION_ATTR = 'data-wave89u-diag-action';
const DIAG_ANSWER_INDEX_ATTR = 'data-wave89u-diag-answer-index';

//
// INIT SUBJECT GRID
//
(function initGrid(){
  const grid = document.getElementById('subj-grid');
  SUBJECTS.forEach((s,i)=>{
    const card = document.createElement('div');
    card.className = 'scard fu';
    card.style.cssText = `--c:${s.color};animation-delay:${i*0.05}s`;
    card.innerHTML = `<div class="scard-ic">${s.icon}</div>
      <div class="scard-nm">${s.name}</div>
      <div class="scard-cl">${s.sub}</div>
      <div class="scard-desc">${s.desc}</div>`;
    card.onclick = ()=>startDiag(s.id);
    grid.appendChild(card);
  });
})();

//
// START DIAGNOSTIC
//
function startDiag(subjId){
  curSubject = SUBJECTS.find(s=>s.id===subjId);
  const pool = sanitizePool(QBANK[subjId]);
  if(!pool.length){ alert('Вопросы скоро появятся!'); return; }

  // Build grade range
  const grades = [...new Set(pool.map(q=>q.g).filter(Number.isFinite))].sort((a,b)=>a-b);
  const minG = grades[0], maxG = grades[grades.length-1];
  curGrade = Math.floor((minG+maxG)/2);

  // Init stats
  gradeStats = {};
  grades.forEach(g=>{ gradeStats[g]={ok:0,total:0,topics:[]}; });

  // Adaptive question selection
  questions = buildAdaptiveSequence(pool, grades, Math.min(MAX_Q, pool.length));
  qIndex = 0;
  answers = [];
  correctStreak = 0;
  wrongStreak = 0;

  // UI
  document.getElementById('quiz-subj-name').textContent = curSubject.name;
  document.getElementById('quiz-subj-sub').textContent = curSubject.sub;
  document.documentElement.style.setProperty('--c', curSubject.color);

  go('quiz');
  renderQ();
}

function buildAdaptiveSequence(pool, grades, maxQ){
  // Pre-group by grade, shuffle each
  const byGrade = {};
  grades.forEach(g=>{ byGrade[g] = shuffle(pool.filter(q=>q.g===g)); });
  grades = grades.filter(g => byGrade[g] && byGrade[g].length > 0);
  if(!grades.length) return [];

  const used = new Set();
  const seq = [];
  let g = curGrade;
  const minG = Math.min(...grades), maxG = Math.max(...grades);
  let safety = 0;

  for(let i=0;i<maxQ;i++){
    if(++safety > 100) break;
    if(!grades.includes(g)) g = grades.reduce((a,b)=>Math.abs(b-g)<Math.abs(a-g)?b:a);

    let available = byGrade[g] ? byGrade[g].filter(q=>!used.has(q)) : [];

    if(!available.length){
      // Exhausted this grade — find nearest grade with questions
      let found = false;
      for(let offset=1;offset<=grades.length;offset++){
        for(const dir of [1,-1]){
          const tryG = g + offset*dir;
          const av = byGrade[tryG] ? byGrade[tryG].filter(q=>!used.has(q)) : [];
          if(av.length){ available=av; g=tryG; found=true; break; }
        }
        if(found) break;
      }
      if(!available.length) break; // No more questions anywhere
    }

    const q = available[0];
    used.add(q);
    seq.push(q);

    // Default fill with mild upward bias; real adjustment happens after each answer
    if(i < Math.ceil(maxQ*0.6)) g = Math.min(g+1, maxG);
    else g = Math.max(g-1, minG);
  }

  return seq;
}

//
// RENDER QUESTION
//
function renderQ(){
  if(qIndex >= questions.length){ showResult(); return; }

  const q = questions[qIndex];
  const total = questions.length;

  // Progress
  document.getElementById('q-prog').textContent = `${qIndex+1} / ${total}`;
  document.getElementById('qbar-fill').style.width = `${Math.round(qIndex/total*100)}%`;
  document.getElementById('grade-pill').textContent = `${q.g} класс`;
  document.getElementById('q-topic').textContent = q.topic;
  document.getElementById('q-txt').textContent = q.q;
  document.getElementById('hint-box').className = 'hint-box';
  document.getElementById('hint-box').textContent = '';
  document.getElementById('next-btn').className = 'next-btn';
  document.getElementById('skip-btn').style.display = 'block';

  // Adaptive strip
  renderStrip();

  // Options
  const opts = document.getElementById('opts');
  const shuffled = shuffle(q.opts);
  window._curShuffled = shuffled;
  window._curAnswer = q.a;
  window._curHint = q.hint;
  opts.innerHTML = shuffled.map((o,i)=>`
    <button class="opt" type="button" ${DIAG_ACTION_ATTR}="answer" ${DIAG_ANSWER_INDEX_ATTR}="${i}">${esc(o)}</button>
  `).join('');
}

function selectOptIdx(btn, idx){
  const chosen = window._curShuffled[idx];
  const correct = window._curAnswer;
  const hint = window._curHint;
  selectOpt(btn, chosen, correct, hint);
}

function esc(s){ return (s+'').replace(/'/g,"&#39;").replace(/"/g,"&quot;"); }

function renderStrip(){
  const strip = document.getElementById('adapt-strip');
  const total = questions.length;
  strip.innerHTML = questions.map((q,i)=>{
    let cls='adapt-dot';
    if(i<qIndex){
      const ans=answers.find(a=>a.qi===i);
      cls+=' '+(ans&&ans.correct?'done-ok':'done-no');
    } else if(i===qIndex) cls+=' current';
    return `<div class="${cls}" title="${q.g}кл"></div>`;
  }).join('') + `<span class="adapt-label">${questions[qIndex]?questions[qIndex].g+'кл':''}</span>`;
}

function selectOpt(btn, chosen, correct, hint){
  // Lock all options
  document.querySelectorAll('.opt').forEach(b=>b.disabled=true);
  const isOk = chosen===correct;

  btn.className = 'opt '+(isOk?'ok':'no');
  if(!isOk){
    document.querySelectorAll('.opt').forEach(b=>{
      if(b.textContent.trim()===correct) b.className='opt ok';
      else if(b!==btn) b.className='opt dim';
    });
  }

  // Hint
  if(!isOk){
    const hb = document.getElementById('hint-box');
    hb.textContent = '💡 ' + hint;
    hb.className = 'hint-box show';
  }

  // Record
  const q = questions[qIndex];
  gradeStats[q.g] = gradeStats[q.g]||{ok:0,total:0,topics:[]};
  gradeStats[q.g].total++;
  if(isOk) gradeStats[q.g].ok++;
  if(!isOk && !gradeStats[q.g].topics.includes(q.topic)) gradeStats[q.g].topics.push(q.topic);
  answers.push({qi:qIndex, grade:q.g, topic:q.topic, correct:isOk});

  // Adaptive: adjust next question grade
  if(isOk){ correctStreak++; wrongStreak = 0; } else { wrongStreak++; correctStreak = 0; }
  adaptNext(isOk);

  document.getElementById('next-btn').className='next-btn show';
  document.getElementById('skip-btn').style.display='none';
}

function skipQ(){
  if(qIndex >= questions.length) return;
  const q = questions[qIndex];
  gradeStats[q.g] = gradeStats[q.g] || {ok:0,total:0,topics:[]};
  gradeStats[q.g].total++;
  if(!gradeStats[q.g].topics.includes(q.topic)) gradeStats[q.g].topics.push(q.topic);
  answers.push({qi:qIndex, grade:q.g, topic:q.topic, correct:false, skipped:true});
  wrongStreak++;
  correctStreak = 0;
  adaptNext(false);
  qIndex++;
  renderQ();
}

function adaptNext(wasCorrect){
  if(window.__wave30ActivePack) return;
  const pool = sanitizePool(QBANK[curSubject.id]);
  const usedQs = new Set(questions.map(q=>q.q));
  const allGrades = [...new Set(pool.map(q=>q.g).filter(Number.isFinite))].sort((a,b)=>a-b);
  if(!allGrades.length) return;

  const curQ = questions[qIndex];
  const minGrade = allGrades[0];
  const maxGrade = allGrades[allGrades.length - 1];
  const jumpUp = wasCorrect ? (correctStreak >= 2 ? 2 : 1) : 0;
  const jumpDown = wasCorrect ? 0 : (wrongStreak >= 2 ? 2 : 1);
  const nextGrade = wasCorrect
    ? Math.min(maxGrade, curQ.g + jumpUp)
    : Math.max(minGrade, curQ.g - jumpDown);

  const candidates = pool.filter(q=>q.g===nextGrade && !usedQs.has(q.q));

  if(candidates.length){
    const pick = candidates[Math.floor(Math.random()*candidates.length)];
    if(qIndex+1 < questions.length){
      questions[qIndex+1] = pick;
    } else if(questions.length < 20){
      // Extend sequence if it was short
      questions.push(pick);
    }
  }
}

function nextQ(){
  qIndex++;
  renderQ();
}

function confirmExit(){
  if(qIndex===0||confirm('Выйти? Прогресс не сохранится.')){ go('select'); }
}

