function showResult(){
  document.getElementById('res-subj-name').textContent = curSubject.name + ' · ' + curSubject.sub;
  go('result');

  // Compute grade levels
  const gradeList = Object.entries(gradeStats).sort((a,b)=>+a[0]-+b[0]);
  const tested = gradeList.filter(([,s])=>s.total>0);

  // Hero
  const totalOk = tested.reduce((s,[,g])=>s+g.ok,0);
  const totalQ  = tested.reduce((s,[,g])=>s+g.total,0);
  const pct = totalQ ? Math.round(totalOk/totalQ*100) : 0;

  let emoji, title, sub;
  if(pct>=80){ emoji='🎉'; title='Отлично!'; sub='Глубокое знание предмета. Несколько пробелов — разбери их и будет идеально.'; }
  else if(pct>=60){ emoji='💪'; title='Хороший уровень'; sub='Базу знаешь, но есть пробелы в отдельных классах. Смотри карту ниже.'; }
  else if(pct>=40){ emoji='📚'; title='Есть над чем поработать'; sub='Заметные пробелы. Хорошая новость — ты теперь точно знаешь, что повторять.'; }
  else { emoji='🌱'; title='Начинаем с основ'; sub='Материал по некоторым классам нужно разобрать с нуля. Всё решаемо!'; }

  document.getElementById('res-emoji').textContent = emoji;
  document.getElementById('res-title').textContent = title;
  document.getElementById('res-sub').textContent = sub;

  // Grade map
  const map = document.getElementById('grade-map');
  map.innerHTML = '';

  // All grades in range
  const allGrades = [...new Set((QBANK[curSubject.id]||[]).map(q=>q.g))].filter(g=>g!==undefined).sort((a,b)=>a-b);

  allGrades.forEach(g=>{
    const s = gradeStats[g];
    const row = document.createElement('div');
    row.className = 'grow';

    if(!s || s.total===0){
      row.className+=' not-tested';
      row.innerHTML = `<div class="gnum">${g} кл</div>
        <div class="gbar-wrap"><div class="gbar" style="width:0%"></div></div>
        <div class="gscore" style="color:var(--muted)">—</div>`;
    } else {
      const p = Math.round(s.ok/s.total*100);
      const color = p>=75?'var(--green)':p>=50?'var(--orange)':'var(--red)';
      const label = p>=75?'Знаю':p>=50?'Частично':'Пробел';
      row.innerHTML = `<div class="gnum">${g} кл</div>
        <div class="gbar-wrap">
          <div class="gbar" style="width:${p}%;background:${color};transition:width 1s ${allGrades.indexOf(g)*0.08}s ease">
            <span class="gbar-label">${label}</span>
          </div>
        </div>
        <div class="gscore">${s.ok}/${s.total}</div>`;
    }
    map.appendChild(row);
  });

  // Gaps
  const gaps = tested.filter(([,s])=>s.total>0 && s.ok/s.total<0.5);
  const gapsList = document.getElementById('gaps-list');
  if(gaps.length){
    document.getElementById('gaps-block').style.display='block';
    gapsList.innerHTML = gaps.map(([g,s])=>`
      <div class="ins-row">
        <span>🔴</span>
        <div><b>${g} класс</b> — ${Math.round(s.ok/s.total*100)}% (${s.ok}/${s.total})
        ${s.topics.length ? '<br><span style="color:var(--muted);font-size:12px">Слабые темы: '+s.topics.join(', ')+'</span>' : ''}</div>
      </div>`).join('');
  } else {
    document.getElementById('gaps-block').style.display='none';
  }

  // Strengths
  const strong = tested.filter(([,s])=>s.total>0 && s.ok/s.total>=0.75);
  const strongList = document.getElementById('strong-list');
  if(strong.length){

  // Training links for weak grades
  const trainDiv = document.getElementById('train-links');
  if(gaps.length && trainDiv){
    const links = gaps.map(([g,s])=>{
      const file = 'grade'+g+'_v2.html';
      return '<a href="'+file+'" class="train-link" style="display:inline-flex;align-items:center;gap:6px;padding:8px 14px;background:var(--card);border:1.5px solid var(--border);border-radius:10px;text-decoration:none;color:var(--text);font-size:13px;font-weight:600">📖 '+g+' класс</a>';
    }).join(' ');
    trainDiv.innerHTML = '<div style="margin-top:10px;display:flex;flex-wrap:wrap;gap:8px">'+links+'</div>';
  }

  document.getElementById('strong-block').style.display='block';
    strongList.innerHTML = strong.map(([g,s])=>`
      <div class="ins-row">
        <span>✅</span>
        <div><b>${g} класс</b> — ${Math.round(s.ok/s.total*100)}% (${s.ok}/${s.total})</div>
      </div>`).join('');
  } else {
    document.getElementById('strong-block').style.display='none';
  }

  // Recommendations
  const recList = document.getElementById('rec-list');
  const recs = [];

  if(gaps.length){
    const worstGrade = gaps.sort((a,b)=>a[1].ok/a[1].total-b[1].ok/b[1].total)[0];
    recs.push(`<div class="ins-row"><span>📌</span><div>Начни с <b>${worstGrade[0]} класса</b> — там самый большой пробел. Открой тренажёр ${worstGrade[0]} класса и проработай слабые темы: ${worstGrade[1].topics.slice(0,3).join(', ') || 'все темы раздела'}.</div></div>`);
  }

  if(strong.length && gaps.length){
    const maxStrong = Math.max(...strong.map(([g])=>+g));
    const minGap = Math.min(...gaps.map(([g])=>+g));
    if(minGap < maxStrong){
      recs.push(`<div class="ins-row"><span>⚠️</span><div>Обрати внимание: ты знаешь материал <b>${maxStrong} класса</b>, но есть пробел в <b>${minGap} классе</b>. Закрой базу — и старший материал станет крепче.</div></div>`);
    }
  }

  if(pct>=75){
    recs.push(`<div class="ins-row"><span>🚀</span><div>Уровень уверенный! Попробуй диагностику по другому предмету или тренажёр следующего класса.</div></div>`);
  }

  if(!recs.length){
    recs.push(`<div class="ins-row"><span>📖</span><div>Занимайся по 15 минут в день в тренажёре — через месяц заметишь разницу.</div></div>`);
  }

  recList.innerHTML = recs.join('');

  // Store for share
  window._diagResult = {subj:curSubject, gradeStats, pct, totalOk, totalQ, tested, gaps, strong};
}

function shareResult(){
  const r = window._diagResult;
  if(!r) return;

  let text = `📊 Диагностика: ${r.subj.name}\n`;
  text += `Итого: ${r.totalOk}/${r.totalQ} (${r.pct}%)\n\n`;
  text += `Карта знаний:\n`;

  r.tested.forEach(([g,s])=>{
    const p = Math.round(s.ok/s.total*100);
    const icon = p>=75?'✅':p>=50?'⚠️':'🔴';
    text += `${icon} ${g} класс: ${p}% (${s.ok}/${s.total})\n`;
  });

  if(r.gaps.length){
    text += `\n⚠️ Пробелы: ${r.gaps.map(([g])=>g+' кл').join(', ')}\n`;
  }
  if(r.strong.length){
    text += `✅ Знает уверенно: ${r.strong.map(([g])=>g+' кл').join(', ')}\n`;
  }

  if(navigator.share){
    navigator.share({title:'Диагностика: '+r.subj.name, text}).catch(()=>copyText(text));
  } else {
    copyText(text);
  }
}

function copyText(text){
  navigator.clipboard&&navigator.clipboard.writeText(text)
    .then(()=>alert('✅ Скопировано! Вставь в сообщение.'))
    .catch(()=>prompt('Скопируй:',text));
}

function findDiagnosticActionNode(node){
  for(let el=node;el&&el!==document;el=el.parentElement){
    if(el.nodeType===1&&el.hasAttribute&&el.hasAttribute(DIAG_ACTION_ATTR)) return el;
  }
  return null;
}

function runDiagnosticRuntimeAction(el, event){
  if(!el || el.disabled) return;
  const action = el.getAttribute(DIAG_ACTION_ATTR) || '';
  if(!action) return;
  if(event && typeof event.preventDefault === 'function') event.preventDefault();
  if(action === 'answer'){
    const idx = Number(el.getAttribute(DIAG_ANSWER_INDEX_ATTR));
    if(Number.isInteger(idx)) selectOptIdx(el, idx);
  }
}

function bindDiagnosticRuntimeActions(){
  if(document.__wave89uDiagnosticRuntimeBound) return;
  document.__wave89uDiagnosticRuntimeBound = true;
  document.addEventListener('click', event=>{
    const el = findDiagnosticActionNode(event.target);
    if(!el) return;
    runDiagnosticRuntimeAction(el, event);
  }, true);
}

window.wave89uDiagnosticBinding = {
  actionAttr: DIAG_ACTION_ATTR,
  answerIndexAttr: DIAG_ANSWER_INDEX_ATTR,
  handle: runDiagnosticRuntimeAction,
  isBound: ()=>!!document.__wave89uDiagnosticRuntimeBound
};

function bindDiagnosticAction(action, handler){
  document.querySelectorAll('[data-wave87r-action="'+action+'"]').forEach(el=>{
    if(el.__wave87rDiagnosticBound) return;
    el.__wave87rDiagnosticBound = true;
    const run = event=>{
      if(event) event.preventDefault();
      handler(event);
    };
    el.addEventListener('click', run);
    if(el.tagName !== 'BUTTON' && el.tagName !== 'A'){
      el.addEventListener('keydown', event=>{
        if(event.key === 'Enter' || event.key === ' ' || event.key === 'Spacebar') run(event);
      });
    }
  });
}

function bindDiagnosticActions(){
  bindDiagnosticAction('confirm-exit', ()=>confirmExit());
  bindDiagnosticAction('diag-next', ()=>nextQ());
  bindDiagnosticAction('diag-skip', ()=>skipQ());
  bindDiagnosticAction('go-select', ()=>go('select'));
  bindDiagnosticAction('diag-share', ()=>shareResult());
}

bindDiagnosticRuntimeActions();
bindDiagnosticActions();
